			for _, flag := range cmd.Flags {
				subCmd.Flags().StringP(flag.Name, flag.Shorthand, flag.DefaultValue, flag.Description)
				if flag.Required {
					subCmd.MarkFlagRequired(flag.Name)
				}
			}
			modCmd.AddCommand(subCmd)
		}

		rootCmd.AddCommand(modCmd)
	}
}

